                                  <span style={{
                                    display: 'inline-block',
                                    width: '10px',
                                    height: '10px',
                                    borderRadius: '50%',
                                    background: '#ef4444',
                                    animation: 'pulse 1.5s ease-in-out infinite'
                                  }}></span>
                                  Recording... Say: "{standardSentence}"
                                </div>
                              )}
                              {uploading && recordingParticipant === p.email && (
                                <div style={{
                                  color: '#60a5fa',
                                  fontSize: '13px',
                                  fontWeight: '600',
                                  display: 'flex',
                                  alignItems: 'center',
                                  gap: '6px',
                                  marginTop: '8px'
                                }}>
                                  <span className="loading-spinner" style={{ width: '12px', height: '12px', borderWidth: '2px' }}></span>
                                  Processing... Detecting your name and assigning voice profile...
                                </div>
                              )}
                            </div>
                            <button
                              type="button"
                              className="btn btn-secondary"
                              onClick={() => {
                                if (isRecording) {
                                  stopVoiceRecording();
