                              disabled={recordingParticipant && recordingParticipant !== p.email}
                              style={{
                                padding: '10px 18px',
                                fontSize: '14px',
                                minWidth: '140px',
                                fontWeight: '600'
                              }}
                            >
                              {isRecording ? '⏹️ Stop Recording' : (hasProfile ? '🔄 Re-record' : '🎤 Record Voice')}
                            </button>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}

                <button type="submit" className="btn btn-primary" disabled={loading}>
                  {loading ? 'Creating...' : 'Create Meeting'}
                </button>
              </form>
            </div>

            {selectedMeeting && (
              <div className="card">
                <div className="card-header">
