                  {selectedMeeting.status === 'Scheduled' && (
                    <button
                      type="button"
                      className="btn btn-secondary"
                      onClick={async () => {
                        try {
                          const res = await axios.post(`/meetings/${selectedMeeting._id}/start`);
                          setSelectedMeeting(res.data.meeting);
                          fetchMeetings();
                          // Navigate to meeting in progress page
                          navigate(`/meetings/${selectedMeeting._id}`);
                        } catch (err) {
                          console.error('Error starting meeting:', err);
                          let serverError =
                            err.response?.data?.error ||
                            err.response?.data?.details ||
                            err.message;
                          setError(serverError || 'Failed to start meeting');
                        }
                      }}
                    >
                      Start Meeting
                    </button>
                  )}
                </div>

                {selectedMeeting.status !== 'Completed' && (
                  <div className="form-group-inline" style={{ marginTop: '8px' }}>
                    <button
                      type="button"
                      className="btn btn-danger"
                      onClick={async () => {
                        try {
                          const res = await axios.post(`/meetings/${selectedMeeting._id}/end`);
                          setSelectedMeeting(res.data.meeting);
                          fetchMeetings();

                          // If transcription is enabled, start polling for summary completion
                          if (res.data.meeting.transcriptionEnabled) {
                            setPolling(true);
                            pollForSummary(res.data.meeting._id);
                          } else {
                            // No transcription, redirect to home immediately
                            setTimeout(() => navigate('/'), 2000);
                          }
                        } catch (err) {
                          console.error('Error ending meeting:', err);
                          let serverError =
                            err.response?.data?.error ||
                            err.response?.data?.details ||
                            err.message;
                          setError(serverError || 'Failed to end meeting');
                        }
                      }}
