                    padding: '32px', 
                    textAlign: 'center',
                    marginTop: '20px'
                  }}>
                    <div style={{ fontSize: '48px', marginBottom: '16px' }}>✅</div>
                    <h3 style={{ color: 'white', marginBottom: '8px', fontSize: '20px', fontWeight: '600' }}>Summary Sent Successfully!</h3>
                    <p style={{ color: 'rgba(255, 255, 255, 0.9)', fontSize: '15px' }}>
